#include <stdio.h>
#include <string.h>
#define MAX 15

int min(int a, int b) { return a < b ? a : b; }

int lcs(char *s1, char *s2, int m) {
    int dp[m + 1][m + 1];
    for (int i = 0; i <= m; i++) {
        for (int j = 0; j <= m; j++) {
            if (i == 0 || j == 0)
                dp[i][j] = 0;
            else if (s1[i - 1] == s2[j - 1])
                dp[i][j] = dp[i - 1][j - 1] + 1;
            else
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
        }
    }
    return dp[m][m];
}

int main() {
    int T, n, m;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        char s[n][MAX], omen[MAX];
        for (int i = 0; i < n; i++)
            scanf("%s", s[i]);
        scanf("%d", &m);
        int min_lcs = n * m;
        for (int mask = 0; mask < (1 << m); mask++) {
            for (int i = 0; i < m; i++)
                omen[i] = (mask & (1 << i)) ? 'b' : 'a';
            omen[m] = '\0';
            int max_lcs_for_omen = 0;
            for (int i = 0; i < n; i++)
                max_lcs_for_omen = max(max_lcs_for_omen, lcs(s[i], omen, m));
            min_lcs = min(min_lcs, max_lcs_for_omen);
        }
        printf("%d\n", min_lcs);
    }
    return 0;
}

