import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            String[] s = new String[n];
            for (int i = 0; i < n; i++)
                s[i] = sc.next();
            int m = s[0].length();
            int min_lcs = n * m;
            for (int mask = 0; mask < (1 << m); mask++) {
                StringBuilder omen = new StringBuilder();
                for (int i = 0; i < m; i++)
                    omen.append((mask & (1 << i)) == 0 ? 'a' : 'b');
                int max_lcs_for_omen = 0;
                for (int i = 0; i < n; i++)
                    max_lcs_for_omen = Math.max(max_lcs_for_omen, lcs(s[i], omen.toString()));
                min_lcs = Math.min(min_lcs, max_lcs_for_omen);
            }
            System.out.println(min_lcs);
        }
    }

    public static int lcs(String s1, String s2) {
        int m = s1.length();
        int[][] dp = new int[m + 1][m + 1];
        for (int i = 0; i <= m; i++) {
            for (int j = 0; j <= m; j++) {
                if (i == 0 || j == 0)
                    dp[i][j] = 0;
                else if (s1.charAt(i - 1) == s2.charAt(j - 1))
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                else
                    dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
            }
        }
        return dp[m][m];
    }
}

